/**
 * @summary Update push token for a user
 */
export const getUpdatePushTokenUrl = (userId: string) => {
  return `/api/users/${userId}/push-token`;
};

export const updatePushToken = async (
  userId: string,
  updatePushTokenBody: UpdatePushTokenBody,
  options?: RequestInit,
): Promise<SuccessResponse> => {
  return customFetch<SuccessResponse>(getUpdatePushTokenUrl(userId), {
    ...options,
    method: "PATCH",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(updatePushTokenBody),
  });
};

export const getUpdatePushTokenMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updatePushToken>>,
    TError,
    { userId: string; data: BodyType<UpdatePushTokenBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updatePushToken>>,
  TError,
  { userId: string; data: BodyType<UpdatePushTokenBody> },
  TContext
> => {
  const mutationKey = ["updatePushToken"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updatePushToken>>,
    { userId: string; data: BodyType<UpdatePushTokenBody> }
  > = (props) => {
    const { userId, data } = props ?? {};

    return updatePushToken(userId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdatePushTokenMutationResult = NonNullable<
  Awaited<ReturnType<typeof updatePushToken>>
>;
export type UpdatePushTokenMutationBody = BodyType<UpdatePushTokenBody>;
export type UpdatePushTokenMutationError = ErrorType<unknown>;

